/// Generates UUID v4 compliant identifiers using Dart's Random class.
/// Suitable for offline data entries that will be synced later.
class UUIDGenerator {
  final Random _random;

  UUIDGenerator({Random? random})
      : _random = random ?? Random.secure();

  /// Generates a single UUID v4 string.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is any hex digit and y is one of 8, 9, a, or b.
  String generate() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) — high nibble of byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) — high bits of byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a batch of UUIDs for bulk offline record creation.
  List<String> generateBatch(int count) {
    return List<String>.generate(count, (_) => generate());
  }

  /// Generates a short ID (first 8 characters of a UUID) for display purposes.
  String generateShortId() {
    final uuid = generate();
    return uuid.substring(0, 8);
  }

  /// Generates a timestamp-prefixed UUID for sortable offline entries.
  /// Format: <timestamp_hex>-<uuid>
  String generateTimestampPrefixed() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final timestampHex = timestamp.toRadixString(16).padLeft(12, '0');
    final uuid = generate();
    return '$timestampHex-$uuid';
  }

  String _formatAsUUID(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates if a string is a valid UUID v4 format.
  static bool isValidUUID(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }
}

/// Represents an offline data entry with a generated UUID.
class OfflineRecord {
  final String id;
  final String title;
  final DateTime createdAt;
  final bool isSynced;
  final String idType;

  OfflineRecord({
    required this.id,
    required this.title,
    required this.createdAt,
    this.isSynced = false,
    this.idType = 'UUID v4',
  });

  OfflineRecord copyWith({bool? isSynced}) {
    return OfflineRecord(
      id: id,
      title: title,
      createdAt: createdAt,
      isSynced: isSynced ?? this.isSynced,
      idType: idType,
    );
  }
}

