  @override
  void dispose() {
    _titleController.dispose();
    _batchCountController.dispose();
    _tabController.dispose();
    super.dispose();
  }

  void _generateNewUUID() {
    setState(() {
      switch (_selectedIdType) {
        case 'UUID v4':
          _currentUUID = _generator.generate();
          break;
        case 'Short ID':
          _currentUUID = _generator.generateShortId();
          break;
        case 'Timestamp Prefixed':
          _currentUUID = _generator.generateTimestampPrefixed();
          break;
      }
    });
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Copied: $text'),
        duration: const Duration(seconds: 2),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _createOfflineRecord() {
    final title = _titleController.text.trim();
    if (title.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please enter a record title'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    String id;
    switch (_selectedIdType) {
      case 'Short ID':
        id = _generator.generateShortId();
        break;
      case 'Timestamp Prefixed':
        id = _generator.generateTimestampPrefixed();
        break;
      default:
        id = _generator.generate();
    }

    setState(() {
      _records.insert(
        0,
        OfflineRecord(
          id: id,
          title: title,
          createdAt: DateTime.now(),
          idType: _selectedIdType,
        ),
      );
      _titleController.clear();
    });

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Record created with ID: ${id.substring(0, min(id.length, 20))}...'),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _generateBatch() {
    final count = int.tryParse(_batchCountController.text) ?? 5;
    if (count < 1 || count > 100) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please enter a number between 1 and 100'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    setState(() {
      _generatedBatch.clear();
      _generatedBatch.addAll(_generator.generateBatch(count));
    });
  }

  void _simulateSync() {
    setState(() {
      for (int i = 0; i < _records.length; i++) {
        if (!_records[i].isSynced) {
          _records[i] = _records[i].copyWith(isSynced: true);
        }
      }
    });

    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(
        content: Text('All records synced successfully!'),
        behavior: SnackBarBehavior.floating,
        backgroundColor: Colors.green,
      ),
    );
  }

  void _clearRecords() {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Clear All Records'),
        content: const Text('Are you sure you want to delete all offline records?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text('Cancel'),
          ),
          TextButton(
            onPressed: () {
              setState(() => _records.clear());
              Navigator.pop(context);
            },
            child: const Text('Clear', style: TextStyle(color: Colors.red)),
          ),
        ],
      ),
    );
  }

